<?php
 declare(strict_types=1); namespace tapmeppe\composer\blueprint; class ResponseAPI { function acknowledge(int $code = 200, bool $exit = true): void { $this->resolve([], $code, $exit); } function answer(mixed $data, array $meta = [], int $code = 200, bool $exit = true): void { $this->resolve(compact('data', 'meta'), $code, $exit); } function confirm(array $meta = [], int $code = 200, bool $exit = true): void { $this->resolve(['success' => true, 'meta' => $meta], $code, $exit); } function download(string $file, int $duration = 604800 * 52): void { $name = basename($file); if (is_file($file)) { ob_start(); ob_clean(); header_remove(); header("Cache-Control: public, max-age=$duration, must-revalidate"); header('Content-Type: application/octet-stream'); header("Content-Disposition: attachment; filename=\"$name\""); header('Content-Length: ' . filesize($file)); flush(); readfile($file); exit(); } else $this->reject(Reason::file, ["File \"$name\" not found."]); } function interupt(...$data): void { if (TAPMEPPE_MODE_DEVELOPMENT) $this->reject(Reason::interupted, $data, 503); } function reject(Reason $reason, array $data = [], int $code = 400, bool $exit = true): void { $this->resolve( [ 'error' => $reason, 'data' => TAPMEPPE_MODE_DEVELOPMENT ? implode("\n", $data) : '', ], $code, $exit ); } function renounce(Reason $reason, array $message = [], int $code = 400, bool $exit = true): void { Utilities::report(compact('reason', 'message', 'code', 'exit')); $this->reject($reason, $message, $code, $exit); } private function resolve(mixed $payload, int $code = 200, bool $exit = true): void { ob_start(); ob_clean(); header_remove(); header("Content-Type: application/json; charset=utf-8"); http_response_code($code); echo json_encode($payload); if ($exit) exit(); } } 